// ============================================================
// frontend/src/pages/NuevaSolicitud.jsx
// Formulario premium para crear solicitudes
// ============================================================
import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { MOCK_SOLICITUDES } from '../services/mockData';
import { useToast } from '../components/Toast';

// Tabla de niveles de aprobación
const NIVELES = [
  { rango: 'Hasta $1.000.000',   nivel: 'Jefe inmediato' },
  { rango: 'Hasta $10.000.000',  nivel: 'Jefe + Gerente' },
  { rango: 'Más de $10.000.000', nivel: 'Jefe + Gerente + Director Financiero' },
];

export default function NuevaSolicitud() {
  const [form, setForm] = useState({
    titulo: '',
    descripcion: '',
    monto: '',
    tipo: 'compra',
  });
  const [error, setError] = useState('');
  const [enviando, setEnviando] = useState(false);
  const navigate = useNavigate();
  const toast = useToast();

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');

    if (parseFloat(form.monto) <= 0) {
      return setError('El monto debe ser mayor a $0.');
    }

    setEnviando(true);

    // Simular creación
    setTimeout(() => {
      const nuevaSolicitud = {
        id: MOCK_SOLICITUDES.length + 1,
        ...form,
        monto: parseFloat(form.monto),
        estado: 'Pendiente',
        fecha: new Date().toISOString().split('T')[0],
        solicitante: 'Jorlin Developer',
        departamento: 'Desarrollo Frontend',
        nivel: parseFloat(form.monto) <= 1000000 ? 'Jefe inmediato'
             : parseFloat(form.monto) <= 10000000 ? 'Jefe + Gerente'
             : 'Jefe + Gerente + Director Financiero',
      };
      MOCK_SOLICITUDES.push(nuevaSolicitud);

      toast.success('¡Solicitud creada!', `"${form.titulo}" ha sido enviada a la cadena de aprobación.`);
      setEnviando(false);
      navigate('/solicitudes');
    }, 800);
  };

  // Calcular niveles de aprobación según monto
  const montoNum = parseFloat(form.monto) || 0;
  const nivelesAplicables = montoNum <= 0 ? [] :
    montoNum <= 1000000   ? [NIVELES[0]] :
    montoNum <= 10000000  ? [NIVELES[0], NIVELES[1]] :
                            [NIVELES[0], NIVELES[1], NIVELES[2]];

  return (
    <div style={{ maxWidth: 640 }}>
      {/* Back Link */}
      <Link to="/solicitudes" className="back-link">
        ← Volver a Solicitudes
      </Link>

      {/* Header */}
      <div className="page-header" style={{ marginBottom: 24 }}>
        <div>
          <h2 className="page-header__title">Nueva Solicitud</h2>
          <p className="page-header__subtitle">
            Completa el formulario. La solicitud entrará automáticamente en la cadena de aprobación según el monto.
          </p>
        </div>
      </div>

      {/* Error */}
      {error && (
        <div className="form-error">
          <svg viewBox="0 0 24 24" width="16" height="16" stroke="currentColor" fill="none" strokeWidth="2" strokeLinecap="round">
            <circle cx="12" cy="12" r="10"/><line x1="15" y1="9" x2="9" y2="15"/><line x1="9" y1="9" x2="15" y2="15"/>
          </svg>
          {error}
        </div>
      )}

      {/* Form */}
      <form onSubmit={handleSubmit}>
        <div className="form-group">
          <label className="form-label">Título de la solicitud <span>*</span></label>
          <input
            name="titulo"
            className="form-input"
            value={form.titulo}
            onChange={handleChange}
            required
            placeholder="Ej: Compra de papelería para el área de ventas"
          />
        </div>

        <div className="form-group">
          <label className="form-label">Descripción detallada <span>*</span></label>
          <textarea
            name="descripcion"
            className="form-textarea"
            value={form.descripcion}
            onChange={handleChange}
            required
            placeholder="Describe qué se va a comprar, para qué y por qué es necesario..."
          />
        </div>

        <div className="form-row">
          <div className="form-group">
            <label className="form-label">Monto (COP $) <span>*</span></label>
            <input
              name="monto"
              type="number"
              className="form-input"
              value={form.monto}
              onChange={handleChange}
              required
              min="1"
              placeholder="0"
            />
          </div>
          <div className="form-group">
            <label className="form-label">Tipo de solicitud <span>*</span></label>
            <select
              name="tipo"
              className="form-select"
              value={form.tipo}
              onChange={handleChange}
            >
              <option value="compra">Compra</option>
              <option value="gasto">Gasto</option>
            </select>
          </div>
        </div>

        {/* Vista previa de la cadena de aprobación */}
        {nivelesAplicables.length > 0 && (
          <div className="approval-chain">
            <div className="approval-chain__title">
              Cadena de aprobación para ${Number(form.monto).toLocaleString('es-CO')} COP:
            </div>
            {nivelesAplicables.map((n, i) => (
              <div key={i} className="approval-chain__step">
                <span className="approval-chain__number">{i + 1}</span>
                <span className="approval-chain__label">{n.nivel}</span>
              </div>
            ))}
          </div>
        )}

        <button
          type="submit"
          className="btn btn--primary btn--full btn--lg"
          disabled={enviando}
        >
          {enviando ? (
            <>
              <div className="btn__spinner" />
              Enviando solicitud...
            </>
          ) : (
            <>
              <svg viewBox="0 0 24 24" width="18" height="18" stroke="currentColor" fill="none" strokeWidth="2" strokeLinecap="round">
                <line x1="22" y1="2" x2="11" y2="13"/><polygon points="22,2 15,22 11,13 2,9 22,2"/>
              </svg>
              Enviar Solicitud
            </>
          )}
        </button>
      </form>
    </div>
  );
}
